	@Test
	void budgetedSortMetricsPublishOnlyOnAttemptCommit() {
		long packedBefore = NativeSortBuffer.PACKED_ROWS.get();
		long sortsBefore = NativeSortBuffer.SORTS.get();
		long candidatesBefore = NativeSortBuffer.TOP_K_CANDIDATES.get();
		long replacementsBefore = topKReplacements();
		PackedRowComparator comparator = (left, leftOffset, right, rightOffset) -> Long.compare(
				left[leftOffset], right[rightOffset]);

		LmdbNativeAttemptMetrics discarded = LmdbNativeAttemptMetrics.root();
		exerciseBudgetedSortMetrics(discarded, comparator);
		assertThat(NativeSortBuffer.PACKED_ROWS.get()).isEqualTo(packedBefore);
		assertThat(NativeSortBuffer.SORTS.get()).isEqualTo(sortsBefore);
		assertThat(NativeSortBuffer.TOP_K_CANDIDATES.get()).isEqualTo(candidatesBefore);
		assertThat(topKReplacements())
				.as("an abandoned optimized attempt must publish no replacement work")
				.isEqualTo(replacementsBefore);

		LmdbNativeAttemptMetrics committed = LmdbNativeAttemptMetrics.root();
		exerciseBudgetedSortMetrics(committed, comparator);
		committed.commitToParent();
		assertThat(NativeSortBuffer.PACKED_ROWS.get()).isEqualTo(packedBefore + 2L);
		assertThat(NativeSortBuffer.SORTS.get()).isEqualTo(sortsBefore + 2L);
		assertThat(NativeSortBuffer.TOP_K_CANDIDATES.get()).isEqualTo(candidatesBefore + 2L);
		assertThat(topKReplacements()).isEqualTo(replacementsBefore + 1L);
	}

