	@Test
	public void topKPayloadStoreCloseReleasesSuccessfulReservationsExactlyOnce() throws Exception {
		FactorizedTail.MemoBudget budget = new FactorizedTail.MemoBudget(new AtomicLong());
		assertThat(budget.tryReserve(FactorizedTail.MEMO_MAX_ENTRIES - 1,
				FactorizedTail.MEMO_MAX_STORED_VALUES - 17)).isTrue();
		TopKPayloadStore payloads = new TopKPayloadStore(1, budget);
		FlatRowCursor cursor = new FlatRowCursor() {
			private final int[] valueSlots = { 0 };
			private final long[] values = { 42 };

			@Override
			public boolean next() {
				return false;
			}

			@Override
			public long multiplicity() {
				return 1;
			}

			@Override
			public int enumCount() {
				return 1;
			}

			@Override
			public int[] enumValueSlots(int i) {
				return valueSlots;
			}

			@Override
			public long[] enumValues(int i) {
				return values;
			}

			@Override
			public long enumMatches(int i) {
				return 1;
			}

			@Override
			public void close() {
			}
		};

		assertThat(payloads.store(0, cursor, 1, new long[2], 0)).isTrue();
		assertThat(payloads.retainedCapacity()).isEqualTo(16);
		assertThat(budget.tryReserve(1, 1)).isFalse();

		Object closeableCandidate = payloads;
		assertThat(closeableCandidate).isInstanceOf(AutoCloseable.class);
		AutoCloseable closeable = (AutoCloseable) closeableCandidate;
		closeable.close();
		closeable.close();

		assertThat(payloads.retainedCapacity()).isZero();
		assertThat(budget.tryReserve(1, 17))
				.as("close must release the payload and its one-slot reference metadata")
				.isTrue();
		assertThat(budget.tryReserve(1, 17))
				.as("a repeated close must not release the same reservation twice")
				.isFalse();
	}

	@Test
	public void topKReplacementChurnRetainsOnlyOneLiveSlotPayload() {
		FactorizedTail.MemoBudget budget = new FactorizedTail.MemoBudget(new AtomicLong());
		assertThat(budget.tryReserve(FactorizedTail.MEMO_MAX_ENTRIES - 1,
				FactorizedTail.MEMO_MAX_STORED_VALUES - 17)).isTrue();
		PackedRowComparator comparator = (left, leftOffset, right, rightOffset) -> Long.compare(
				left[leftOffset], right[rightOffset]);
		NativeTopKBuffer topK = new NativeTopKBuffer(4, 1, comparator);
		long[][] values = { new long[4] };
		StubFlatRowCursor cursor = new StubFlatRowCursor(new int[][] { { 0 } }, values, new long[] { 4 });

		try (TopKPayloadStore payloads = new TopKPayloadStore(1, budget)) {
			for (int i = 0; i < 512; i++) {
				long[] packed = { 512L - i, 1L, 0L, 0L };
				int acceptedSlot = topK.admit(packed, i, 2);
				assertThat(acceptedSlot)
						.as("monotonically improving candidate %s should replace the K=1 winner", i)
						.isZero();
				for (int j = 0; j < values[0].length; j++) {
					values[0][j] = i + j;
				}
				assertThat(payloads.store(acceptedSlot, cursor, 1, packed, 2))
						.as("replacement %s must reuse the live slot's existing payload array", i)
						.isTrue();
				topK.replaceAcceptedSuffix(acceptedSlot, packed, 2);
				assertThat(payloads.retainedCapacity())
						.as("retained payload capacity after replacement %s", i)
						.isEqualTo(16);
			}

			long[] winner = new long[4];
			topK.buffer.copyRow(0, winner);
			long[] retained = new long[4];
			payloads.copyTo(0, winner[2], retained, 0, retained.length);
			assertThat(winner[0]).isEqualTo(1);
			assertThat(retained).containsExactly(511, 512, 513, 514);
		}
	}

